var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"사건번호 078853 <color=#ffd34c>알파트릭스 시큐리티 폭파 사건</color>\\n증거물 11호 - 통화 녹취록","JPN":"事件番号078853 <color=#ffd34c>アルファトリックスセキュリティ爆破事件</color>\\n証拠物件11号 - 通話録音記録","ENG":"[[","TWN":"案件編號 078853 <color=#ffd34c>阿爾法崔克斯證券爆炸事件</color>\\n證物11號 - 電話錄音紀錄","THA":"หมายเลขเคส 078853 <color=#ffd34c>เหตุการณ์การระเบิดของฝ่ายรักษาความปลอดภัยอัลฟาทริกซ์</color>\\nเอกสารแนบ 11 - ประวัติการโทร","VTN":"<color=#ffd34c>ARC-KS1</color>\\nCụm Rạp Trung Tâm. ■ năm trước.","SCN":"案件编号 078853<color=#ffd34c>阿尔法崔克斯安全爆炸案</color>\\n11号证据-通话录音","DEU":"Fallnummer 078853 <color=#ffd34c>Alphatrix Security-Explosionsvorfall</color>\\nAnlage 11 – Anrufprotokolle","FRA":"Affaire N°078853 <color=#ffd34c>Explosion à Alphatrix Security</color>\\nPièce à conviction 11 -  Historique d'appels"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"……그래. 자네 말대로 그 사람들이 여기 온 건 사실이야.","JPN":"……そうだ。君の言うとおり、あの者たちがここに来たのは事実だ。","ENG":"...Yes, it's like you said. They're here right now.","TWN":"……沒錯，就是你說的那樣，那些人在這裡。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"하지만 대체 어떻게 알고 연락한 건가?","JPN":"だが、いったいどうやって知ったんだ？","ENG":"But how did you know to call me?","TWN":"但你是如何得知的？而且還找上我？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"회장님의 권한이면 그룹 전산망에 연결된 모든 장비의 데이터를 열람할 수 있습니다.","JPN":"会長の権限ならグループのネットワークに繋がれているすべての装備のデータを閲覧できます。","ENG":"With the President's authority, we have access to all data on any device that is connected to the company network.","TWN":"會長的權限可以瀏覽所有連上集團網路的裝備裡的數據，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"임직원용 어플리케이션이 설치된 이사님의 핸드폰도 말이죠.","JPN":"役員用のアプリがインストールされている常務のスマートフォンも例外ではありません。","ENG":"Including your phone that has the employee application installed on it.","TWN":"而理事您的手機裡也有安裝員工專屬的APP。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그렇다면 시큐리티 시스템이 갑자기 작동했던 것도……","JPN":"では、セキュリティシステムが突然作動したのも……","ENG":"Then the security system suddenly going off is also...","TWN":"那保安系統會突然啟動也是……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 둘 다 돌아가신 전 회장님의 유품이죠.","JPN":"はい。両方とも亡くなった元会長の遺産です。","ENG":"Yes. They are both mementos left behind by the late President.","TWN":"是的，這二個都是已故會長的遺物。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그런가…… 평생을 바친 회사인데 까맣게 모르고 있었군.","JPN":"そうか……生涯を捧げた会社なのにまったく知らなかったな。","ENG":"I see... I've pledged my whole life to this company, and I never knew.","TWN":"是嗎……原來我對奉獻一生的公司一無所知。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"저희는 알파트릭스 시큐리티에 침입한 민병대를 경찰에 인계할 계획입니다.","JPN":"私たちはアルファトリックスセキュリティに進入した民兵隊を警察に引き渡すつもりです。","ENG":"We plan to turn in the Militia who broke into Alphatrix Security to the police.","TWN":"我們打算將入侵阿爾法崔克斯證券的民兵隊交給警方。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"좋아. 시간을 주면 내가 먼저 그들을 설득해 보겠네.","JPN":"わかった。時間をくれれば私がまず彼らを説得してみよう。","ENG":"OK. Give me some time so that I can persuade them.","TWN":"好吧，給我點時間，我會去說服他們。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"위험한 자들입니다. 이사님이 인질로 잡히실 수도 있어요.","JPN":"危険な者たちです。常務が人質になるかもしれません。","ENG":"They are dangerous folk. You could become their hostage.","TWN":"他們是危險分子，很可能會抓您來當人質。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"자신들이 막다른 골목에 몰렸다는 것만 알려 주면 돼.","JPN":"自分たちが袋小路に陥っているということさえ知らせられればいい。","ENG":"I just need to tell them that they're cornered and can't escape.","TWN":"我會跟他們說，他們已經無路可退，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"경찰과 총격전을 벌이다 죽느니 자수하는 게 더 낫다는 건 본인들이 가장 잘 알겠지.","JPN":"警察との銃撃戦の末に死ぬよりは自首した方がいいということは自分たちが一番よくわかっているだろう。","ENG":"They'll know it's better to turn themselves in than to start a shootout with the police.","TWN":"與其在和警方的槍戰中死亡，自首才是更好的選擇，這一點他們自己應該最清楚，"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"이제까지 지은 죄가 있다지만, 그 편이 형량도 더 낮게…….","JPN":"今まで犯してきた罪があったとしても、その方が量刑も軽く……","ENG":"This way, they might get a lighter sentence for all their si─","TWN":"他們是有犯罪的事實，這樣或許可以減輕刑責……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"여보세요? 이사님, 제 말 들리시나요?","JPN":"もしもし？　常務、聞こえますか？","ENG":"Hello? Sir? Are you there?","TWN":"喂？理事，您有聽到我的聲音嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"무슨 일이죠? 대답해 보세요!","JPN":"どうされましたか？　答えてください！","ENG":"What's going on? Please answer me!","TWN":"發生什麼事？請您回答我！"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};